mapper.select:
select from cook_recipes r inner join cook_recipe_versions v on v.id = r.current_version_id and v.deleted_at is null inner join cook_users u on u.id = r.author_id and u.deleted_at is null where r.deleted_at is null and r.publish_status = 'online' and v.status = 'published'
and r.category_code = #{categoryCode}
and v.difficulty = #{difficulty}
and (v.title like concat('%', #{keyword}, '%') or v.intro like concat('%', #{keyword}, '%'))
order by
case when r.category_code in
#{code}
then 0 else 1 end,
r.updated_at desc, r.id desc

select from cook_recipes r inner join cook_recipe_versions v on v.recipe_id = r.id and v.version_no = (select max(rv.version_no) from cook_recipe_versions rv where rv.recipe_id = r.id and rv.deleted_at is null) and v.deleted_at is null inner join cook_users u on u.id = r.author_id and u.deleted_at is null where r.deleted_at is null and r.author_id = #{authorId}
and v.status = #{status}
order by r.updated_at desc, r.id desc

select from cook_recipes r inner join cook_recipe_versions v on v.recipe_id = r.id and v.version_no = (select max(rv.version_no) from cook_recipe_versions rv where rv.recipe_id = r.id and rv.deleted_at is null) and v.deleted_at is null inner join cook_users u on u.id = r.author_id and u.deleted_at is null where r.deleted_at is null
and r.review_status = #{reviewStatus}
and r.publish_status = #{publishStatus}
and (v.title like concat('%', #{keyword}, '%') or u.nickname like concat('%', #{keyword}, '%'))
order by r.updated_at desc, r.id desc

mapper.update:
update cook_recipes
set deleted_at = current_timestamp,
    updated_at = current_timestamp
where id = #{id}
  and author_id = #{authorId}
  and deleted_at is null
